function report = runPaperStudy(options)
%RUNPAPERSTUDY Audit, render, or evaluate an allowed P2 study case.
%
% Evaluate modes preserve primary and diagnostic-only outputs separately.
% Held-out modes fail while the preregistration state is locked.
% Traceability: algo/main.tex unified experimental program; implementation
% plan P2 step 2.

arguments
    options.Mode (1, 1) string ...
        {mustBeMember(options.Mode, ...
        ["audit", "plan-tuning", "plan-heldout", ...
        "render-tuning", "render-heldout", ...
        "evaluate-tuning", "evaluate-heldout"])} = "audit"
    options.StudyFile (1, 1) string = ...
        PaperStudyContract.defaultStudyFile
    options.CaseIdentifier (1, 1) string = ""
    options.WorkingPrecision (1, 1) string ...
        {mustBeMember(options.WorkingPrecision, ...
        ["single", "double"])} = "single"
    options.DerivativeSigma (1, 1) double ...
        {mustBeFinite, mustBePositive} = 1.2
    options.IntegrationSigma (1, 1) double ...
        {mustBeFinite, mustBePositive} = 2
    options.MaximumConditionNumber (1, 1) double ...
        {mustBeFinite, mustBePositive} = 10000
    options.GradientEnergyPercentile (1, 1) double ...
        {mustBeFinite, mustBeNonnegative} = 10
    options.IncludeDiagnostics (1, 1) logical = true
    options.Verbose (1, 1) logical = true
end

root = fileparts(fileparts(mfilename("fullpath")));
oldPath = path;
addpath(fullfile(root, "src"));
cleanup = onCleanup(@() path(oldPath));
contract = PaperStudyContract(options.StudyFile);
audit = contract.audit;
switch options.Mode
    case "audit"
        cases = table;
        rendered = struct;
    case {"plan-tuning", "render-tuning", "evaluate-tuning"}
        cases = contract.tuningCases;
        rendered = struct;
    case {"plan-heldout", "render-heldout", "evaluate-heldout"}
        cases = contract.heldoutCases;
        rendered = struct;
end
sparse = struct;
diagnostics = struct;
scientific = struct;
constructCase = startsWith(options.Mode, "render-") ...
    || startsWith(options.Mode, "evaluate-");
if constructCase
    if strlength(options.CaseIdentifier) == 0
        error("runPaperStudy:CaseIdentifierRequired", ...
            "Render/evaluate modes require one CaseIdentifier " ...
            + "from the allowed plan.");
    end
    id = find(cases.Identifier == options.CaseIdentifier);
    if numel(id) ~= 1
        error("runPaperStudy:UnknownCaseIdentifier", ...
            "CaseIdentifier '%s' is not in the allowed %s plan.", ...
            options.CaseIdentifier, options.Mode);
    end
    cases = cases(id, :);
    c = PaperStudySyntheticCase(cases, contract.Manifest);
    rendered = c.render(WorkingPrecision=options.WorkingPrecision);
    if startsWith(options.Mode, "evaluate-")
        evaluator = PaperStudySparseEvaluator(contract.Manifest);
        sparse = evaluator.evaluate(rendered, ...
            DerivativeSigma=options.DerivativeSigma, ...
            IntegrationSigma=options.IntegrationSigma);
        if options.IncludeDiagnostics
            diagnostics = evaluator.evaluateDiagnostics(rendered, ...
                DerivativeSigma=options.DerivativeSigma, ...
                IntegrationSigma=options.IntegrationSigma, ...
                MaximumConditionNumber= ...
                options.MaximumConditionNumber, ...
                GradientEnergyPercentile= ...
                options.GradientEnergyPercentile);
        end
        scientific = struct( ...
            "PrimarySummary", sparse.Summary, ...
            "DiagnosticOutputsIncluded", options.IncludeDiagnostics);
        stage = "single-case unregularized primary and diagnostic evaluation";
    else
        stage = ...
            "common case rendering and exact truth only; no costs evaluated";
    end
else
    stage = "contract audit and plan only; no rendering or evaluation";
end
report = struct( ...
    "Mode", options.Mode, ...
    "Stage", stage, ...
    "Audit", audit, ...
    "Cases", cases, ...
    "CaseCount", height(cases), ...
    "RenderedCase", rendered, ...
    "SparseEvaluation", sparse, ...
    "DiagnosticEvaluation", diagnostics, ...
    "HeldoutAccessed", endsWith(options.Mode, "heldout"), ...
    "ScientificResults", scientific);
if options.Verbose
    fprintf("P2 %s: %s, state %s\n", ...
        options.Mode, audit.Identifier, audit.State);
    fprintf("  tuning/heldout cases: %d/%d; heldout allowed: %s\n", ...
        audit.TuningCaseCount, audit.HeldoutCaseCount, ...
        string(audit.HeldoutAccessAllowed));
    if ~isempty(cases) && startsWith(options.Mode, "plan-")
        disp(cases)
    elseif constructCase
        fprintf("  rendered %s: %d labels, %d/%d truth-valid samples\n", ...
            rendered.Identifier, numel(rendered.HeightLabelsMetres), ...
            nnz(rendered.TruthValid), numel(rendered.TruthValid));
        if startsWith(options.Mode, "evaluate-")
            disp(sparse.Summary)
            fprintf("  primary/diagnostic runtime: %.3f/%.3f s\n", ...
                sparse.EvaluationSeconds.Total, ...
                diagnosticSeconds(diagnostics));
        end
    end
end
clear cleanup
end

function seconds = diagnosticSeconds(diagnostics)
if isempty(fieldnames(diagnostics))
    seconds = 0;
else
    seconds = diagnostics.EvaluationSeconds.Total;
end
end
